import { agenticAiFeatures } from "@/data/agentic-ai";
import React from "react";

export default function Features() {
  return (
    <div className="wg-create-design style-6 pt-130">
      <div className="themesflat-container">
        <div className="row">
          <div className="col-lg-6">
            <div className="content">
              <div className="heading-section wow fadeInUp">
                <h6>What We Provide</h6>
                <div className="main-title">
                  AI Agents That Execute
                  <br />
                  Construction Logistics
                  <br />
                  <span className="tf-color-green">Autonomously</span>
                </div>
              </div>
              <p className="">
                From RFQ generation to shipment tracking, our agentic AI
                <br />
                handles the heavy lifting so your team can focus on building.
              </p>
            </div>
          </div>
          <div className="col-lg-6">
            <div className="row">
              {agenticAiFeatures.map((item, index) => (
                <div className="col-xl-4 col-6" key={index}>
                  <div className="wg-helpful text-center mb-30 wow fadeInUp">
                    <div className="image">
                      <span className={item.icon} />
                    </div>
                    <h6>{item.title}</h6>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
